WITH pixel_ship AS (SELECT SUM(shipped_units) AS shipped_units FROM shipped_raw WHERE item_name ILIKE '%pixel%'), pixel_conc AS (SELECT SUM(conceded_units) AS conceded_units FROM concession_raw WHERE item_name ILIKE '%pixel%'), iphone_ship AS (SELECT SUM(shipped_units) AS shipped_units FROM shipped_raw WHERE item_name ILIKE '%iphone%'), iphone_conc AS (SELECT SUM(conceded_units) AS conceded_units FROM concession_raw WHERE item_name ILIKE '%iphone%') SELECT 'Google Pixel' AS group_name, ps.shipped_units, pc.conceded_units, (pc.conceded_units * 100.0) / NULLIF(ps.shipped_units, 0) AS return_rate_pct FROM pixel_ship ps CROSS JOIN pixel_conc pc UNION ALL SELECT 'iPhone' AS group_name, ish.shipped_units, ic.conceded_units, (ic.conceded_units * 100.0) / NULLIF(ish.shipped_units, 0) AS return_rate_pct FROM iphone_ship ish CROSS JOIN iphone_conc ic;